<div class="page-title-row"><div><h1>Asset History</h1><p class="text-muted mb-0">A unified timeline for vehicles and equipment.</p></div></div><div class="row g-4"><div class="col-lg-4"><div class="portal-card"><h2>Add Activity</h2><form method="post" action="/portal/asset-history" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Asset</label><select class="form-select" id="assetChoice" required><?php foreach($assets as $a):?><option data-type="<?=e($a['asset_type'])?>" value="<?=$a['id']?>"><?=e($a['asset_name'])?> (<?=e($a['asset_type'])?>)</option><?php endforeach?></select><input type="hidden" name="asset_type" id="assetType"><input type="hidden" name="asset_id" id="assetId"></div><div class="col-12"><label class="form-label">Activity</label><input name="activity_type" class="form-control" placeholder="inspection, repair, assignment..." required></div><div class="col-12"><label class="form-label">Summary</label><input name="summary" class="form-control" required></div><div class="col-12"><label class="form-label">Notes</label><textarea name="notes" class="form-control"></textarea></div><div class="col-12"><button class="btn btn-primary w-100">Add Timeline Entry</button></div></form></div></div><div class="col-lg-8"><div class="portal-card"><div class="activity-list"><?php foreach($activities as $a):?><div class="border-bottom py-3"><div class="d-flex justify-content-between"><strong><?=e($a['asset_name']??'Unknown asset')?></strong><small><?=e($a['occurred_at'])?></small></div><div><?=e($a['summary'])?></div><small class="text-muted"><?=e($a['activity_type'])?> · <?=e($a['performed_name']??'System')?></small></div><?php endforeach?><?php if(!$activities):?><p class="text-muted">No asset activity has been recorded.</p><?php endif?></div></div></div></div><script>document.addEventListener('DOMContentLoaded',()=>{const s=document.getElementById('assetChoice'),t=document.getElementById('assetType'),i=document.getElementById('assetId');function sync(){const o=s.options[s.selectedIndex];t.value=o.dataset.type;i.value=o.value}sync();s.addEventListener('change',sync)});</script>
